from abc import ABC, abstractmethod
from dataclasses import dataclass


class PaymentProcessor(ABC):
    @abstractmethod
    def charge(self, customer_id: str, amount: float, currency: str) -> bool: ...
    @abstractmethod
    def refund(self, transaction_id: str, amount: float) -> bool: ...

class LegacyPaymentGateway:
    def make_payment(self, amount_cents: int, currency_code: str, client_ref: str) -> int:
        print(f"  [Legacy] Charging {amount_cents} cents ({currency_code}) for {client_ref}")
        return 12345
    def reverse_payment(self, txn_number: int) -> bool:
        print(f"  [Legacy] Reversing #{txn_number}")
        return True

class LegacyPaymentAdapter(PaymentProcessor):
    def __init__(self, legacy: LegacyPaymentGateway):
        self._legacy = legacy
        self._txn_map: dict[str, int] = {}

    def charge(self, customer_id: str, amount: float, currency: str) -> bool:
        cents = int(amount * 100)
        txn_id = self._legacy.make_payment(cents, currency.upper(), customer_id)
        self._txn_map[f"TXN-{txn_id}"] = txn_id
        print(f"  [Adapter] Mapped TXN-{txn_id}")
        return txn_id > 0

    def refund(self, transaction_id: str, amount: float) -> bool:
        legacy_id = self._txn_map.get(transaction_id)
        if legacy_id is None: return False
        return self._legacy.reverse_payment(legacy_id)


if __name__ == "__main__":
    print("=== Adapter Pattern Demo ===")
    processor: PaymentProcessor = LegacyPaymentAdapter(LegacyPaymentGateway())
    processor.charge("CUST-001", 49.99, "usd")
```

### When to Use vs When NOT to Use

- **Use when**: Integrating third-party libraries or legacy systems with incompatible interfaces. When you cannot modify source code.
- **Avoid when**: Interfaces are already compatible. When you can modify the source directly.

### Interview Questions

1. **"Adapter vs Facade?"** -- Adapter converts one interface to another (1:1). Facade simplifies a complex subsystem (1:many).
2. **"Object Adapter vs Class Adapter?"** -- Object uses composition (preferred). Class uses multiple inheritance.
3. **"Real example?"** -- Wrapping a legacy SOAP service with REST, adapting API response formats.

### Real-World Examples

- **Java**: `Arrays.asList()` adapts array to List. `InputStreamReader` adapts byte to char streams.
- **Python**: `csv.DictReader` adapts CSV rows to dictionaries.
- **Spring**: `HandlerAdapter` adapts controller types to `DispatcherServlet`.

## Facade Pattern

The Facade pattern provides a simplified, unified interface to a complex subsystem. Instead of requiring clients to interact with dozens of classes, the facade exposes a few high-level methods that orchestrate the subsystem internally.

### What Problem Does It Solve?

Placing an order involves inventory checking, payment processing, shipping, notifications, and analytics. Without a facade, client code must coordinate all these services. The Facade hides this behind a single `placeOrder()` call.

### UML / Structure

```mermaid
classDiagram
    class OrderFacade {
        +placeOrder(order): OrderResult
    }
    class InventoryService { +checkStock() +reserve() }
    class PaymentService { +charge() }
    class ShippingService { +createShipment() }
    class NotificationService { +sendEmail() }
    OrderFacade --> InventoryService
    OrderFacade --> PaymentService
    OrderFacade --> ShippingService
    OrderFacade --> NotificationService
```

### Java Implementation

```java
import java.util.*;

class InventoryService {
    private final Map<String, Integer> stock = new HashMap<>(Map.of("laptop", 10, "mouse", 50));
    public boolean checkStock(String item, int qty) {
        int avail = stock.getOrDefault(item, 0);
        System.out.printf("  [Inventory] %s: %d available, need %d%n", item, avail, qty);
        return avail >= qty;
    }
    public void reserve(String item, int qty) {
        stock.merge(item, -qty, Integer::sum);
        System.out.printf("  [Inventory] Reserved %d x %s%n", qty, item);
    }
    public void release(String item, int qty) {
        stock.merge(item, qty, Integer::sum);
    }
}

class PaymentService {
    public String charge(String customerId, double amount) {
        System.out.printf("  [Payment] Charged $%.2f to %s%n", amount, customerId);
        return "TXN-" + System.currentTimeMillis();
    }
}

class ShippingService {
    public String createShipment(String address, List<String> items) {
        String tracking = "SHIP-" + (int)(Math.random() * 100000);
        System.out.println("  [Shipping] Created " + tracking + " to " + address);
        return tracking;
    }
}

class NotificationService {
    public void sendEmail(String to, String subject) {
        System.out.printf("  [Email] To: %s | Subject: %s%n", to, subject);
    }
}

class OrderFacade {
    private final InventoryService inventory = new InventoryService();
    private final PaymentService payment = new PaymentService();
    private final ShippingService shipping = new ShippingService();
    private final NotificationService notification = new NotificationService();

    public record OrderResult(boolean success, String message, String tracking) {}

    public OrderResult placeOrder(String customerId, String email, String address,
                                   Map<String, Integer> items, double total) {
        System.out.println("  === OrderFacade: Starting ===");
        for (var e : items.entrySet())
            if (!inventory.checkStock(e.getKey(), e.getValue()))
                return new OrderResult(false, "Out of stock: " + e.getKey(), null);

        for (var e : items.entrySet()) inventory.reserve(e.getKey(), e.getValue());

        String txnId;
        try {
            txnId = payment.charge(customerId, total);
        } catch (Exception ex) {
            for (var e : items.entrySet()) inventory.release(e.getKey(), e.getValue());
            return new OrderResult(false, "Payment failed", null);
        }

        String tracking = shipping.createShipment(address, new ArrayList<>(items.keySet()));
        notification.sendEmail(email, "Order Confirmed! Tracking: " + tracking);
        return new OrderResult(true, "Success", tracking);
    }
}

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Facade Pattern Demo ===");
        OrderFacade facade = new OrderFacade();

        System.out.println("\n--- Place Order (success) ---");
        var result = facade.placeOrder("CUST-001", "alice@example.com", "123 Main St",
            Map.of("laptop", 1, "mouse", 2), 1299.97);
        System.out.println("  Result: " + result);

        System.out.println("\n--- Place Order (out of stock) ---");
        var result2 = facade.placeOrder("CUST-002", "bob@example.com", "456 Oak Ave",
            Map.of("laptop", 100), 99999.00);
        System.out.println("  Result: " + result2);
    }
}
```

