from dataclasses import dataclass
from typing import Optional
import random

class InventoryService:
    def __init__(self):
        self._stock = {"laptop": 10, "mouse": 50}
    def check_stock(self, item: str, qty: int) -> bool:
        avail = self._stock.get(item, 0)
        print(f"  [Inventory] {item}: {avail} available, need {qty}")
        return avail >= qty
    def reserve(self, item: str, qty: int) -> None:
        self._stock[item] = self._stock.get(item, 0) - qty
        print(f"  [Inventory] Reserved {qty}x {item}")

class PaymentService:
    def charge(self, customer_id: str, amount: float) -> str:
        txn = f"TXN-{random.randint(10000,99999)}"
        print(f"  [Payment] Charged ${amount:.2f} -> {txn}")
        return txn

class ShippingService:
    def create_shipment(self, address: str, items: list[str]) -> str:
        tracking = f"SHIP-{random.randint(10000,99999)}"
        print(f"  [Shipping] {tracking} to {address}")
        return tracking

class NotificationService:
    def send_email(self, to: str, subject: str) -> None:
        print(f"  [Email] To: {to} | {subject}")

@dataclass
class OrderResult:
    success: bool
    message: str
    tracking: Optional[str] = None

class OrderFacade:
    def __init__(self):
        self._inv = InventoryService()
        self._pay = PaymentService()
        self._ship = ShippingService()
        self._notif = NotificationService()

    def place_order(self, cust_id: str, email: str, address: str,
                    items: dict[str, int], total: float) -> OrderResult:
        for item, qty in items.items():
            if not self._inv.check_stock(item, qty):
                return OrderResult(False, f"Out of stock: {item}")
        for item, qty in items.items():
            self._inv.reserve(item, qty)
        self._pay.charge(cust_id, total)
        tracking = self._ship.create_shipment(address, list(items.keys()))
        self._notif.send_email(email, f"Tracking: {tracking}")
        return OrderResult(True, "Success", tracking)

if __name__ == "__main__":
    print("=== Facade Pattern Demo ===")
    facade = OrderFacade()
    print(facade.place_order("C1", "alice@test.com", "123 Main", {"laptop": 1}, 999.99))
```

### When to Use vs When NOT to Use

- **Use when**: Simplifying complex subsystem interactions. Layering your system. Decoupling clients from internals.
- **Avoid when**: The subsystem is already simple. When clients need fine-grained control.

### Interview Questions

1. **"Facade vs Adapter?"** -- Facade simplifies (many to one). Adapter converts (one to one).
2. **"Does Facade violate SRP?"** -- No, its one responsibility is orchestration. It delegates actual work.
3. **"How does Facade relate to microservices?"** -- API Gateway is a Facade for backend microservices.

### Real-World Examples

- **Spring Boot**: `RestTemplate` is a facade over HTTP complexity.
- **Django**: `django.shortcuts.render()` is a facade.
- **AWS SDK**: High-level clients are facades over low-level API operations.

## Command Pattern

The Command pattern encapsulates a request as an object, containing all information needed to perform the action. This allows you to parameterize methods with different requests, queue or log requests, and support undo/redo.

### What Problem Does It Solve?

Consider a text editor. Each user action (type, delete, bold, paste) needs to be undoable. Without Command, you need complex state tracking. With Command, each action is an object with `execute()` and `undo()` methods. A history stack stores executed commands.

### UML / Structure

```mermaid
classDiagram
    class Command {
        <<interface>>
        +execute()
        +undo()
    }
    class InsertTextCommand { +execute() +undo() }
    class DeleteTextCommand { +execute() +undo() }
    class CommandHistory {
        -undoStack: Stack
        -redoStack: Stack
        +execute(cmd)
        +undo()
        +redo()
    }
    Command <|.. InsertTextCommand
    Command <|.. DeleteTextCommand
    CommandHistory --> Command
```

### Java Implementation

```java
import java.util.*;

interface Command {
    void execute();
    void undo();
    String description();
}

class TextEditor {
    private StringBuilder content = new StringBuilder();
    private int cursor = 0;
    public void insertAt(int pos, String text) { content.insert(pos, text); cursor = pos + text.length(); }
    public String deleteAt(int pos, int len) {
        String deleted = content.substring(pos, pos + len);
        content.delete(pos, pos + len); cursor = pos;
        return deleted;
    }
    public int getCursor() { return cursor; }
    public String getContent() { return content.toString(); }
    @Override public String toString() { return "\"" + content + "\" (cursor=" + cursor + ")"; }
}

class InsertTextCommand implements Command {
    private final TextEditor editor;
    private final String text;
    private final int position;
    InsertTextCommand(TextEditor ed, String text) { this.editor = ed; this.text = text; this.position = ed.getCursor(); }
    @Override public void execute() { editor.insertAt(position, text); }
    @Override public void undo() { editor.deleteAt(position, text.length()); }
    @Override public String description() { return "Insert '" + text + "'"; }
}

class DeleteTextCommand implements Command {
    private final TextEditor editor;
    private final int count;
    private final int position;
    private String deletedText;
    DeleteTextCommand(TextEditor ed, int count) {
        this.editor = ed; this.count = count;
        this.position = Math.max(0, ed.getCursor() - count);
    }
    @Override public void execute() { deletedText = editor.deleteAt(position, count); }
    @Override public void undo() { editor.insertAt(position, deletedText); }
    @Override public String description() { return "Delete " + count + " chars"; }
}

class CommandHistory {
    private final Deque<Command> undoStack = new ArrayDeque<>();
    private final Deque<Command> redoStack = new ArrayDeque<>();
    public void execute(Command cmd) { cmd.execute(); undoStack.push(cmd); redoStack.clear(); }
    public boolean undo() {
        if (undoStack.isEmpty()) return false;
        Command cmd = undoStack.pop(); cmd.undo(); redoStack.push(cmd); return true;
    }
    public boolean redo() {
        if (redoStack.isEmpty()) return false;
        Command cmd = redoStack.pop(); cmd.execute(); undoStack.push(cmd); return true;
    }
}

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Command Pattern Demo ===");
        TextEditor editor = new TextEditor();
        CommandHistory history = new CommandHistory();

        System.out.println("\n--- Typing ---");
        history.execute(new InsertTextCommand(editor, "Hello"));
        System.out.println("  " + editor);
        history.execute(new InsertTextCommand(editor, " World"));
        System.out.println("  " + editor);
        history.execute(new InsertTextCommand(editor, "!"));
        System.out.println("  " + editor);

        System.out.println("\n--- Undo x2 ---");
        history.undo(); System.out.println("  " + editor);
        history.undo(); System.out.println("  " + editor);

        System.out.println("\n--- Redo ---");
        history.redo(); System.out.println("  " + editor);

        System.out.println("\n--- Delete 3 chars ---");
        history.execute(new DeleteTextCommand(editor, 3));
        System.out.println("  " + editor);

        System.out.println("\n--- Undo delete ---");
        history.undo(); System.out.println("  " + editor);
    }
}
```

### Python Implementation

```python
from abc import ABC, abstractmethod
from collections import deque

class Command(ABC):
    @abstractmethod
    def execute(self) -> None: ...
    @abstractmethod
    def undo(self) -> None: ...

class TextEditor:
    def __init__(self):
        self._content: list[str] = []
        self.cursor: int = 0
    def insert_at(self, pos: int, text: str) -> None:
        self._content.insert(pos, text); self.cursor = pos + 1
    def delete_at(self, pos: int) -> str:
        deleted = self._content.pop(pos); self.cursor = max(0, pos); return deleted
    @property
    def content(self) -> str: return "".join(self._content)
    def __repr__(self) -> str: return f'"{self.content}" (cursor={self.cursor})'

class InsertCommand(Command):
    def __init__(self, editor: TextEditor, text: str):
        self.editor = editor; self.text = text; self.position = editor.cursor
    def execute(self) -> None: self.editor.insert_at(self.position, self.text)
    def undo(self) -> None: self.editor.delete_at(self.position)

class CommandHistory:
    def __init__(self):
        self._undo: deque[Command] = deque()
        self._redo: deque[Command] = deque()
    def execute(self, cmd: Command) -> None:
        cmd.execute(); self._undo.append(cmd); self._redo.clear()
    def undo(self) -> bool:
        if not self._undo: return False
        cmd = self._undo.pop(); cmd.undo(); self._redo.append(cmd); return True
    def redo(self) -> bool:
        if not self._redo: return False
        cmd = self._redo.pop(); cmd.execute(); self._undo.append(cmd); return True

if __name__ == "__main__":
    print("=== Command Pattern Demo ===")
    editor = TextEditor()
    history = CommandHistory()
    for ch in "Hello World":
        history.execute(InsertCommand(editor, ch))
    print(f"  {editor}")
    for _ in range(5): history.undo()
    print(f"  After 5 undos: {editor}")
    for _ in range(3): history.redo()
    print(f"  After 3 redos: {editor}")
```

### When to Use vs When NOT to Use

- **Use when**: Undo/redo functionality. Request queuing/scheduling. Transaction logging. Macro recording.
- **Avoid when**: Operations are simple and do not need undo.

### Interview Questions

1. **"Command vs Strategy?"** -- Strategy: HOW to do something (algorithm). Command: WHAT to do (a complete request with undo).
2. **"How does Command enable undo/redo?"** -- Each Command stores state to reverse its action. Undo stack tracks history.
3. **"Command and Event Sourcing?"** -- Events are Commands. Current state is rebuilt by replaying.

### Real-World Examples

- **Java Swing**: `Action` interface is Command.
- **Git**: Every operation is a reversible Command.
- **Redux**: Actions are Commands -- `dispatch({type: 'ADD_TODO', payload: ...})`.

## Proxy Pattern

The Proxy pattern provides a surrogate or placeholder for another object to control access to it. The proxy implements the same interface as the real object, so the client cannot tell the difference.

### What Problem Does It Solve?

Proxies solve several problems: (1) **Caching Proxy**: avoid expensive repeated calls. (2) **Access Control Proxy**: check permissions. (3) **Lazy Loading Proxy**: defer expensive initialization. (4) **Logging Proxy**: transparently log operations.

### UML / Structure

```mermaid
classDiagram
    class DataService {
        <<interface>>
        +getData(key): String
        +setData(key, value)
    }
    class RealDataService { +getData() +setData() }
    class CachingProxy { -cache: Map +getData() +setData() }
    class AccessControlProxy { -userRole: String +getData() +setData() }
    DataService <|.. RealDataService
    DataService <|.. CachingProxy
    DataService <|.. AccessControlProxy
    CachingProxy --> DataService
    AccessControlProxy --> DataService
```

### Java Implementation

```java
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

interface DataService {
    String getData(String key);
    void setData(String key, String value);
}

class DatabaseService implements DataService {
    private final Map<String, String> db = new HashMap<>(Map.of(
        "user:1", "Alice", "user:2", "Bob", "config:theme", "dark"));
    @Override public String getData(String key) {
        System.out.println("  [DB] Fetched '" + key + "'");
        return db.get(key);
    }
    @Override public void setData(String key, String value) {
        db.put(key, value);
        System.out.println("  [DB] Stored '" + key + "'");
    }
}

class CachingProxy implements DataService {
    private final DataService real;
    private final Map<String, String> cache = new ConcurrentHashMap<>();
    private int hits = 0, misses = 0;
    CachingProxy(DataService real) { this.real = real; }

    @Override public String getData(String key) {
        if (cache.containsKey(key)) {
            hits++; System.out.println("  [Cache] HIT '" + key + "'");
            return cache.get(key);
        }
        misses++; System.out.println("  [Cache] MISS '" + key + "'");
        String value = real.getData(key);
        cache.put(key, value);
        return value;
    }
    @Override public void setData(String key, String value) {
        cache.remove(key); real.setData(key, value);
    }
    public String stats() {
        int total = hits + misses;
        return String.format("Hits: %d, Misses: %d, Ratio: %.0f%%", hits, misses,
            total > 0 ? 100.0 * hits / total : 0);
    }
}

class AccessControlProxy implements DataService {
    private final DataService real;
    private final String userRole;
    AccessControlProxy(DataService real, String role) { this.real = real; this.userRole = role; }

    @Override public String getData(String key) { return real.getData(key); }
    @Override public void setData(String key, String value) {
        if (!"admin".equals(userRole)) {
            System.out.println("  [Auth] DENIED: '" + userRole + "' cannot write");
            throw new SecurityException("Write denied");
        }
        real.setData(key, value);
    }
}

public class Main {
    public static void main(String[] args) {
        System.out.println("=== Proxy Pattern Demo ===");

        System.out.println("\n--- Caching Proxy ---");
        CachingProxy cached = new CachingProxy(new DatabaseService());
        cached.getData("user:1"); // MISS
        cached.getData("user:1"); // HIT
        cached.getData("user:2"); // MISS
        cached.getData("user:1"); // HIT
        System.out.println("  Stats: " + cached.stats());

        System.out.println("\n--- Access Control Proxy ---");
        DataService viewer = new AccessControlProxy(new DatabaseService(), "viewer");
        viewer.getData("user:1");
        try { viewer.setData("user:1", "Charlie"); }
        catch (SecurityException e) { System.out.println("  Caught: " + e.getMessage()); }
    }
}
```

