from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Optional
import uuid

@dataclass
class User:
    id: str; name: str; email: str
    def is_valid_email(self) -> bool: return "@" in self.email

class UserRepository(ABC):
    @abstractmethod
    def save(self, user: User) -> None: ...
    @abstractmethod
    def find_by_email(self, email: str) -> Optional[User]: ...

class CreateUserUseCase:
    def __init__(self, repo: UserRepository): self._repo = repo
    def execute(self, name: str, email: str) -> User:
        user = User(id=str(uuid.uuid4())[:8], name=name, email=email)
        if not user.is_valid_email(): raise ValueError("Invalid email")
        if self._repo.find_by_email(email): raise ValueError("Email taken")
        self._repo.save(user); return user

class InMemoryUserRepo(UserRepository):
    def __init__(self): self._store: dict[str, User] = {}
    def save(self, user: User) -> None: self._store[user.id] = user
    def find_by_email(self, email: str) -> Optional[User]:
        return next((u for u in self._store.values() if u.email == email), None)

class UserController:
    def __init__(self, create_uc: CreateUserUseCase): self._create = create_uc
    def handle_create(self, name: str, email: str) -> dict:
        try:
            user = self._create.execute(name, email)
            return {"status": 201, "id": user.id}
        except ValueError as e:
            return {"status": 400, "error": str(e)}

if __name__ == "__main__":
    print("=== Clean Architecture Demo ===")
    repo = InMemoryUserRepo()
    ctrl = UserController(CreateUserUseCase(repo))
    print(ctrl.handle_create("Alice", "alice@example.com"))
    print(ctrl.handle_create("Bob", "bob@example.com"))
    print(ctrl.handle_create("Alice2", "alice@example.com"))
