        this.category = category; this.stock = stock;
    }
    public String getId() { return id; }
    public String getName() { return name; }
    public double getPrice() { return price; }
    public String getCategory() { return category; }
    public int getStock() { return stock; }
    @Override public String toString() {
        return String.format("%s($%.2f, %s, stock=%d)", name, price, category, stock);
    }
}

interface ProductRepository {
    Product save(Product p);
    Optional<Product> findById(String id);
    List<Product> findAll();
    List<Product> findByCategory(String cat);
    List<Product> findByPriceRange(double min, double max);
}

class InMemoryProductRepo implements ProductRepository {
    private final Map<String, Product> store = new LinkedHashMap<>();
    @Override public Product save(Product p) { store.put(p.getId(), p); return p; }
    @Override public Optional<Product> findById(String id) { return Optional.ofNullable(store.get(id)); }
    @Override public List<Product> findAll() { return new ArrayList<>(store.values()); }
    @Override public List<Product> findByCategory(String cat) {
        return store.values().stream().filter(p -> cat.equals(p.getCategory())).collect(Collectors.toList());
    }
    @Override public List<Product> findByPriceRange(double min, double max) {
        return store.values().stream().filter(p -> p.getPrice() >= min && p.getPrice() <= max).collect(Collectors.toList());
    }
}

class SqlProductRepo implements ProductRepository {
    private final Map<String, Product> db = new LinkedHashMap<>();
