    }
    @Override public Optional<Product> findById(String id) {
        System.out.println("  [SQL] SELECT * FROM products WHERE id = '" + id + "'");
        return Optional.ofNullable(db.get(id));
    }
    @Override public List<Product> findAll() {
        System.out.println("  [SQL] SELECT * FROM products"); return new ArrayList<>(db.values());
    }
    @Override public List<Product> findByCategory(String cat) {
        System.out.println("  [SQL] SELECT ... WHERE category = '" + cat + "'");
        return db.values().stream().filter(p -> cat.equals(p.getCategory())).collect(Collectors.toList());
    }
    @Override public List<Product> findByPriceRange(double min, double max) {
        System.out.printf("  [SQL] SELECT ... WHERE price BETWEEN %.2f AND %.2f%n", min, max);
        return db.values().stream().filter(p -> p.getPrice() >= min && p.getPrice() <= max).collect(Collectors.toList());
    }
