from dataclasses import dataclass
from typing import Optional

@dataclass
class Product:
    id: str; name: str; price: float; category: str; stock: int

class ProductRepository(ABC):
    @abstractmethod
    def save(self, product: Product) -> Product: ...
    @abstractmethod
    def find_by_category(self, cat: str) -> list[Product]: ...
    @abstractmethod
    def find_by_price_range(self, min_p: float, max_p: float) -> list[Product]: ...

class InMemoryProductRepo(ProductRepository):
    def __init__(self): self._store: dict[str, Product] = {}
    def save(self, p: Product) -> Product: self._store[p.id] = p; return p
    def find_by_category(self, cat: str) -> list[Product]:
        return [p for p in self._store.values() if p.category == cat]
    def find_by_price_range(self, min_p: float, max_p: float) -> list[Product]:
        return [p for p in self._store.values() if min_p <= p.price <= max_p]

class ProductService:
